from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card(credit_card_number, key):
    fernet = Fernet(key)
    encrypted_credit_card = fernet.encrypt(credit_card_number.encode())
    return encrypted_credit_card

def decrypt_credit_card(encrypted_credit_card, key):
    fernet = Fernet(key)
    decrypted_credit_card = fernet.decrypt(encrypted_credit_card).decode()
    return decrypted_credit_card

